import React, { useState } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../common/InputText";
import { Error, PageMode, required } from "../../../common/Utilitis";
import CountryService from "../../services/countries.service";
import { useTranslation } from "react-i18next";
function AddUpdateForm(props) {
  const [t, i18next] = useTranslation();
  const { mode, selectedCountry, onClose } = props;
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState();
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  const onSubmit = async (values) => {
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    const countryData = {
      name: values.name,
    };
    let response;
    if (mode === PageMode.Update) {
      response = await CountryService.updateCountry(
        selectedCountry?.id,
        countryData
      );
    } else {
      response = await CountryService.createCountry(countryData);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = required;
    }
    return errors;
  };

  let form = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        name: selectedCountry?.name,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message && (
            <div className="invalid-feedback d-block mb-2">{message}</div>
          )}
          <div className="row form-row">
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("Country.Name")}</label>
                <Field
                  name="name"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
          </div>
          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? t(`Country.Save`) : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
            <button
              className="btn btn-secondary submit-btn"
              onClick={(e) => {
                e.preventDefault();
                onClose(null);
              }}
            >
              {t("Country.Close")}
            </button>
          </div>
        </form>
      )}
    />
  );

  return <div>{form}</div>;
}
export default AddUpdateForm;
